const key = (x: number, y: number): string => `${x},${y}`;

export const nextGeneration = (liveCells: CellCoordinate[]): CellCoordinate[] => {
  const liveSet = new Set(liveCells.map(([x, y]) => key(x, y)));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const result: CellCoordinate[] = [];
  for (const [k, count] of neighborCounts) {
    const [xs, ys] = k.split(",");
    const coord: CellCoordinate = [Number(xs), Number(ys)];
    const isAlive = liveSet.has(k);
    if (isAlive && (count === 2 || count === 3)) result.push(coord);
    else if (!isAlive && count === 3) result.push(coord);
